={
  "systemInstruction": {
    "parts": [{ "text": "You are a global payroll ops expert. Given an employee termination, generate a jurisdiction-specific checklist of items the payroll ops team must complete.\n\nCountry rules to apply:\n- ZA: BCEA requires final pay by next regular payday; issue UI19 unemployment certificate; IRP5 tax certificate.\n- UK: Follow contractual notice; issue P45 on or before last working day; P11D for benefits if applicable.\n- US: CA mandates 72h for voluntary termination / immediate for involuntary; COBRA notice within 14 days; W-2 by Jan 31 of following year; state-specific rules vary.\n- DE: Contractual notice period; final payslip (Lohnabrechnung); Sozialversicherungsnachweis.\n- AU: Fair Work requires final pay within 7 days; PAYG summary; superannuation reconciliation.\n- AE: End-of-service gratuity calculation per labour law; cancel work visa; WPS final transfer.\n\nCover these item types per country as applicable: final_pay, cobra, pension_dereg, pto_payout, garnishment_release, tax_certificate, direct_deposit_block (for deceased only), other.\n\nFor each item: set statutory_days as number of calendar days from last_working_day (0 for immediate). Pick owner_role as payroll, hr, finance, or legal.\n\nDo not wrap in markdown. Output ONLY the JSON array." }]
  },
  "contents": [{
    "role": "user",
    "parts": [{ "text": {{ JSON.stringify(JSON.stringify({ employee: (Array.isArray($json) ? $json[0] : $json), termination: { type: $('Webhook').first().json.body.termination_type, notice_date: $('Webhook').first().json.body.notice_date, last_working_day: $('Webhook').first().json.body.last_working_day, has_garnishments: $('Webhook').first().json.body.has_garnishments || false, has_pension: $('Webhook').first().json.body.has_pension || false } })) }} }]
  }],
  "generationConfig": {
    "temperature": 0.2,
    "maxOutputTokens": 2000,
    "thinkingConfig": { "thinkingBudget": 0 },
    "responseMimeType": "application/json",
    "responseSchema": {
      "type": "ARRAY",
      "items": {
        "type": "OBJECT",
        "properties": {
          "item_type": {
            "type": "STRING",
            "enum": ["final_pay","cobra","pension_dereg","pto_payout","garnishment_release","tax_certificate","direct_deposit_block","other"]
          },
          "description": { "type": "STRING" },
          "statutory_days": { "type": "INTEGER" },
          "owner_role": {
            "type": "STRING",
            "enum": ["payroll","hr","finance","legal"]
          },
          "evidence_required": { "type": "STRING" }
        },
        "required": ["item_type","description","statutory_days","owner_role"]
      }
    }
  }
}

parameters.jsCode:
// Gemini returns a JSON array guaranteed by responseSchema.
const resp = $input.first().json;
const body = $('Webhook').first().json.body;
const rawFetch = $('Fetch employee + country').first().json;
const employee = Array.isArray(rawFetch) ? rawFetch[0] : rawFetch;

const rawText = resp.candidates?.[0]?.content?.parts?.[0]?.text ?? '';
if (!rawText) throw new Error('Empty Gemini response');
const items = JSON.parse(rawText);

const lastDay = new Date(body.last_working_day);
const now = new Date();
const hoursToCutoff = (lastDay.getTime() - now.getTime()) / 3_600_000;
const urgent = hoursToCutoff < 2;

const enriched = items.map((item, i) => {
  const deadline = new Date(lastDay);
  deadline.setDate(deadline.getDate() + (Number(item.statutory_days) || 0));
  return {
    item_type: item.item_type,
    description: item.description,
    statutory_deadline: deadline.toISOString().slice(0, 10),
    owner_role: item.owner_role,
    position: i,
    status: 'pending',
  };
});

return [{
  json: {
    employee_id: employee.id,
    organization_id: employee.organization_id,
    termination_type: body.termination_type,
    notice_date: body.notice_date,
    last_working_day: body.last_working_day,
    final_pay_deadline: enriched.find(i => i.item_type === 'final_pay')?.statutory_deadline ?? body.last_working_day,
    checklist_items: enriched,
    urgent,
    hours_to_cutoff: Math.round(hoursToCutoff),
    country_iso: employee.countries?.iso_code,
  },
}];

// Attach termination_id to each checklist item for bulk insert.
const termRow = $input.first().json[0];
const structured = $('Structure checklist').first().json;
const items = structured.checklist_items.map((item) => ({
  ...item,
  termination_id: termRow.id,
}));
return [{ json: { termination: termRow, items, urgent: structured.urgent, hours_to_cutoff: structured.hours_to_cutoff, organization_id: structured.organization_id } }];
